    virtual void display() { cout << "Base" << endl; }
    // What is missing here?
};

class Derived : public Base {
    int* moreData;
public:
    Derived() { moreData = new int[100]; }
    ~Derived() { /* What should be here? */ }
    void display() override { cout << "Derived" << endl; }
};

